"""
MKT Original Language Commentary — Proverbs chapters 13–15
Run: python3 scripts/zc-original-proverbs-13-15.py

Source data used:
- data/interlinear/proverbs.json
- data/translation/glossary-hebrew.json (key terms)
- data/translation/draft/mediating/proverbs.json (MKT text)

Key decisions in this range:
- נֶפֶשׁ (nephesh): rendered "soul" when the text treats it as the seat of appetite or
  inner longing (13:2, 4, 19; 14:10); "life" when the referent is the whole person in
  relation to danger or death (13:3, 8). This range distinction is consistent with MKT.
- מוּסָר (mûsār): rendered "discipline" or "instruction" depending on context; the word
  fuses the ideas of correction, training, and the consequential suffering that shapes
  character — narrowing to one English equivalent loses nuance addressed in each note.
- כֹּפֶר (13:8): "ransom" chosen over "redemption price" — preserves the commercial
  exchange imagery without importing Levitical freight prematurely.
- אֶרֶךְ אַפַּיִם (14:29): literally "long of nostrils/anger" — English "slow to anger"
  loses the visceral anatomy of the Hebrew idiom.
- תּוֹעֲבָה (abomination, 15:8, 9, 26): the word signals cultic revulsion, not merely
  moral disapproval; the MKT "detests" captures the emotional register but the cultic
  background is noted below.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PROVERBS = {
  "13": {
    "1": '<p><strong>מוּסָר</strong> (<em>mûsār</em>) is the dominant wisdom term for disciplinary instruction — not merely the transfer of information but formative correction that shapes character through consequence. The <em>ben ḥākām</em> (wise son) heeds it; the <em>lēṣ</em> (mocker/scorner) does not even respond to <em>gəʿārâ</em> (rebuke, a sharp verbal correction). The antithesis is absolute: wisdom begins with teachability.</p>',
    "2": '<p><strong>נֶפֶשׁ</strong> (<em>nephesh</em>) appears twice — the appetite-soul of a person satisfied by the fruit of words (13:2a) and the appetite-soul of the treacherous that craves <em>ḥāmās</em> (violence). The word covers both the deepest self and its hungers; what the inner person feeds on shapes what it becomes. The MKT renders both occurrences as "soul," preserving this continuity.</p>',
    "3": '<p><strong>שֹׁמֵר פִּיו</strong> (guard/watch his mouth) uses the watchman root <em>šāmar</em> — active vigilance, not passive restraint. The contrast is <em>pōśēq śəpātāyw</em> (one who opens wide his lips): the participle <em>pōśēq</em> implies a permanent disposition, a mouth habitually open. The consequence — <em>mehittâ</em> (ruin/terror) — intensifies this: careless speech is not just socially costly but destructive.</p>',
    "4": '<p><strong>נֶפֶשׁ עָצֵל</strong> (soul of the lazy) <strong>אִוָּתָה</strong> (craves, Hithpael of <em>ʾāwâ</em>) — the reflexive stem intensifies the desire: the lazy person craves intensely, but <em>wəʾayin</em> (and nothing). The <em>nephesh ḥārûṣîm</em> (soul of the diligent) is richly satisfied (<em>dušenâ</em>, fat/prosperous). The diligent and the lazy both have deep desire; only one of them acts on it.</p>',
    "5": '<p><strong>שֶׁקֶר</strong> (<em>šeqer</em>, falsehood/lie) is what the righteous person <em>śānēʾ</em> (hates) — hate is the correct moral response to deception. The wicked person <em>yaḇîš</em> (causes shame/stench) and <em>yaḥpîr</em> (brings disgrace) — both verbs have roots in shame and putrefaction; the MKT "acts disgracefully" captures the sense.</p>',
    "6": '<p><strong>צְדָקָה</strong> (<em>ṣedāqâ</em>) and <strong>רִשְׁעָה</strong> (<em>rišʿâ</em>) stand as polar abstractions — righteousness and wickedness as active forces that either guard or overthrow. Both are personified agents in the verse, not merely descriptions. The <em>tammîm dārēk</em> (one of blameless way) is protected by righteousness as though by a sentinel.</p>',
    "7": '<p>The verse is deliberately compressed: one person <em>mitrōšēš</em> (Hithpolel of <em>rāšaš</em>, acts rich) yet has nothing; another <em>mitrôšēš</em> (Hithpael of <em>rûš</em>, acts poor) yet has great wealth. The Hithpael stems signal self-presentation — the verse is about performance and appearance versus reality. Both verbs are rare; the contrast is ironic and the form deliberate.</p>',
    "8": '<p><strong>כֹּפֶר</strong> (<em>kōpher</em>) is the ransom or redemption price — the same word used for the atonement payment in Exod 30:12 and for the price that averts a penalty. Here it is the rich person\'s option: wealth can buy off threats. The poor person, paradoxically, does not hear <em>gəʿārâ</em> (rebuke/threatening) at all — they have nothing to be taken, so they are not threatened. Wealth creates vulnerability as well as security.</p>',
    "9": '<p><strong>אוֹר צַדִּיקִים</strong> (light of the righteous) <strong>יִשְׂמָח</strong> (rejoices/shines brightly) — the verb is the same as "rejoice"; the MKT "shines with joy" bridges the metaphor. The lamp of the wicked is <em>yidʿak</em> (snuffed out, extinguished) — a sudden, complete ending, not gradual dimming.</p>',
    "10": '<p><strong>זָדוֹן</strong> (<em>zādôn</em>, presumptuous pride/arrogance) produces only <em>maṣṣâ</em> (contention/strife). The word translated "pride" carries the sense of deliberate, willful presumption — acting as though one does not need God or others. Wisdom (<em>ḥokmâ</em>) is found with those who <em>niwwāʿăṣîm</em> (take counsel together).</p>',
    "11": '<p><strong>הוֹן מֵהֶבֶל</strong> (wealth from vanity/breath/nothing) — <em>hebel</em> is the same word Ecclesiastes uses for transience and futility; wealth gained that way will similarly vanish (<em>yimʿāṭ</em>, diminish). By contrast, <em>qōbēṣ עַל-יָד</em> (one who gathers hand-by-hand, gradually) will <em>yarbeh</em> (multiply/increase). The contrast is not merely honest vs. dishonest but patient accumulation vs. windfall seeking.</p>',
    "12": '<p><strong>תּוֹחֶלֶת מְמֻשָּׁכָה</strong> (hope drawn out/prolonged) makes the heart <em>ḥolâ</em> (sick) — the verb root is illness, genuine malaise. The contrast is <strong>עֵץ חַיִּים</strong> (<em>ʿēṣ ḥayyîm</em>, tree of life) — the Genesis phrase (2:9; 3:22, 24) for the source of immortal life. A desire fulfilled carries the weight of restored access to life itself; the delay of hope inverts that promise.</p>',
    "13": '<p><strong>בָּז לְדָבָר</strong> (despises the word/matter) — <em>dābār</em> can be word, commandment, or matter; the deliberate ambiguity covers both the spoken word and the commandment. <strong>יֵחָבֶל לוֹ</strong> (will be destroyed for it) — the Niphal passive: destruction comes to the person. <strong>יְרֵא מִצְוָה</strong> (fears/reverences the commandment) will be <em>yəšullam</em> (rewarded/made complete/paid in full).</p>',
    "14": '<p><strong>תּוֹרַת חָכָם</strong> (<em>tôrat ḥākām</em>, teaching/torah of the wise) — the word <em>tôrâ</em> carries its full weight: not a suggestion but an authoritative instruction. It is <em>məqôr ḥayyîm</em> (fountain of life), the same phrase used in Ps 36:9 and Prov 14:27 and 16:22 for God himself as the source of life. The sage\'s instruction participates in that divine vitality.</p>',
    "15": '<p><strong>שֵׂכֶל טוֹב</strong> (good understanding/insight) wins <em>ḥēn</em> (favor/grace/charm) — the same word used for unmerited divine favor in Gen 6:8 and Exod 33:12. The way of the treacherous (<em>בּוֹגְדִים</em>) is <em>ʾêtān</em> (enduring/constant) — the MKT "leads to their ruin" is an interpretation; the Hebrew says their way is "permanent/hard" (suggesting inescapability).</p>',
    "16": '<p><strong>כָּל-עָרוּם</strong> (every prudent/crafty person) acts from <em>dāʿat</em> (knowledge) — the same root as the knowledge of good and evil; here used positively for deliberate, informed action. The fool "broadcasts his foolishness" — the verb <em>yiphrōś</em> (spreads out, makes known) implies involuntary display: the fool cannot help revealing what he is.</p>',
    "17": '<p><strong>מַלְאָךְ רָשָׁע</strong> (messenger of wickedness) — the same word <em>malʾāk</em> used for divine angels; the context determines whether the messenger is holy or corrupt. A faithful envoy (<em>ṣîr ʾĕmûnîm</em>, ambassador of faithfulness) brings <em>marpēʾ</em> (healing/health) — the word covers both physical and relational restoration.</p>',
    "18": '<p><strong>רֵישׁ וְקָלוֹן</strong> (poverty and shame/dishonor) — both are social states, not merely inner ones. The shame (<em>qālôn</em>) that comes with refusing <em>mûsār</em> is public degradation. By contrast, <em>kābôd</em> (honor/weight/glory) comes to the one who accepts <em>tôkaḥat</em> (correction/reproof) — the same word used for God\'s reproof in the Psalms.</p>',
    "19": '<p><strong>תַּאֲוָה נִהְיָה</strong> (longing become/fulfilled) is sweet (<em>ʿārēb</em>) to the <em>nephesh</em> — something satisfied at the depth of the self. The second half: it is <em>tôʿăbat kəsîlîm</em> (abomination/detestable) to fools to turn from evil (<em>sûr mērāʿ</em>). The word <em>tôʿăbâ</em> (abomination) is usually what God finds detestable; here fools find the good itself detestable — the inversion is striking.</p>',
    "20": '<p><strong>הוֹלֵךְ אֶת-חֲכָמִים יֶחְכָּם</strong> (walking with the wise, one becomes wise) — the <em>Qal</em> of <em>ḥākam</em> is not instantaneous; the participle walking suggests an ongoing process of formation. Companionship with fools (<em>rōʿeh kəsîlîm</em>) will be "shattered/broken" — the verb <em>yērôaʿ</em> does not mean merely "suffer harm" but implies the kind of rupture that cannot easily be repaired.</p>',
    "21": '<p><strong>חַטָּאִים</strong> (sinners) are pursued (<em>təraddēp</em>) by calamity — the verb is the same used for military pursuit; sin is stalked by its consequences. The righteous will be <em>yəšallēm-ṭôb</em> (repaid with good) — <em>šālem</em> (wholeness/completion) as the root: the repayment brings them to completeness.</p>',
    "22": '<p><strong>חֵיל חוֹטֵא</strong> (wealth of the sinner) is <em>ṣāpûn laṣṣaddîq</em> (stored up for the righteous) — the passive participle <em>ṣāpûn</em> suggests it has been laid away in secret, reserved. Providence steers the flow of accumulated wealth across generations. The word <em>ṣaddîq</em> occurs in both halves — the good man leaves an inheritance, and the righteous ultimately receive the sinner\'s hoarded wealth.</p>',
    "23": '<p><strong>נִיר רָאשִׁים</strong> (fallow ground / tillage of the poor/heads) is uncertain — the word <em>rāʾšîm</em> can mean either "poor people" (from <em>rûš</em>) or "heads/chiefs." The MKT follows "poor" as more contextually consistent: their land can yield abundant food (<em>ʾōkel</em>) but it is swept away by <em>lōʾ mišpāṭ</em> (injustice, without justice) — the system, not the soil, is the problem.</p>',
    "24": '<p><strong>שֵׁבֶט</strong> (<em>šēbeṭ</em>) is the rod/staff — the same word for a tribe\'s scepter and a shepherd\'s staff. Discipline and authority converge in the image. <strong>חוֹשֵׂךְ שִׁבְטוֹ</strong> (the one who withholds his rod) <strong>שׂוֹנֵא בְנוֹ</strong> (hates his son) — the equation is deliberately shocking. Love (<em>ʾōhăbô</em>, Qal participle, continuous love) disciplines <em>bəšaḥar</em> (diligently/from early on, while there is time).</p>',
    "25": '<p><strong>נֶפֶשׁ צַדִּיק</strong> (soul of the righteous) <strong>תֹּאכַל לְשָׂבַע</strong> (eats to satisfaction) — the imperfect verb is customary: this is habitually true, not just once. The belly (<em>beṭen</em>) of the wicked lacks (<em>teḥsar</em>, is deficient) — the same word for the poverty of hunger. Material prosperity follows the contours of character in the wisdom worldview; the connection is structural, not superstitious.</p>'
  },
  "14": {
    "1": '<p><strong>חָכְמוֹת</strong> (<em>ḥokmôt</em>) is a plural form — often understood as a plural of majesty or intensity, "Lady Wisdom" writ large, the same plural used in 1:20 and 9:1 where Wisdom is personified. The wise woman (<em>ʾēšet ḥāyil</em> implied) builds (<em>bānātâ</em>, perfect: accomplished action) her house; the fool tears it down with her own hands (<em>bəyādehā</em>) — the instrument of destruction is herself.</p>',
    "2": '<p><strong>יְרֵא יהוה</strong> (fearer of the LORD) — the fear-of-YHWH formula; <em>yārēʾ</em> as a participle indicates a settled character, not a momentary fright. The contrast is <em>bôzeh dərākāyw</em> (one who despises his [the LORD\'s] ways) — the suffix "his ways" refers to the LORD\'s ways, not the person\'s own; contempt for God\'s path is contempt for God himself.</p>',
    "3": '<p><strong>בְּפִי-אֱוִיל</strong> (in the mouth of a fool) is a <strong>חֹטֶר גַּאֲוָה</strong> (branch/shoot of pride/arrogance) — <em>ḥōṭer</em> is a twig or rod; the fool\'s speech is itself a weapon of arrogance that strikes back against him. The lips of the wise (<em>śiptê ḥăkāmîm</em>) <em>tišmôrēm</em> (protect them, Qal imperfect) — the lips are both the instrument and the means of protection.</p>',
    "4": '<p><strong>אֵין אֲלָפִים</strong> (where there are no oxen) the <strong>אֵבוּס בָּר</strong> (manger is empty/clean) — the word <em>bār</em> can mean both "clean" and "grain/food." The deliberate ambiguity: clean because empty, or empty of the grain that oxen produce. Much increase (<em>tebûʾat ʿāz</em>, produce of strength) comes from ox power. Productivity requires accepting the mess of living things.</p>',
    "5": '<p><strong>עֵד אֱמוּנִים</strong> (faithful/trustworthy witness) — <em>ʾĕmûnîm</em> carries the covenant-faithfulness register of <em>ʾemet</em> (truth, reliability); the witness is truthful because they are fundamentally oriented toward reality. The false witness (<em>ʾēd šeqer</em>, a witness of <em>šeqer</em>, falsehood/deceit) breathes out (<em>yāpîaḥ</em>) lies — the breathing metaphor suggests effortless, habitual production of deception.</p>',
    "6": '<p>The mocker (<em>lēṣ</em>) seeks (<em>biqqēš</em>, Piel: deliberate seeking) wisdom but does not find it. Knowledge comes easily (<em>nāqāl</em>, is light/swift) to the person of understanding (<em>nābôn</em>). The <em>lēṣ</em>\'s problem is not intellectual incapacity but the prior moral stance — contempt for correction (see 13:1) that closes the mind to wisdom before the seeking begins.</p>',
    "7": '<p><strong>לֵךְ מִנֶּגֶד</strong> (go from before) is a strong spatial imperative: physically remove yourself from the fool\'s presence. The reason: <strong>בַּל-יָדַעְתָּ שִׂפְתֵי-דָעַת</strong> — there are no lips of knowledge on him; knowledge is not present to his mouth. The negative <em>bal</em> (never/certainly not) is stronger than simple <em>lōʾ</em>.</p>',
    "8": '<p><strong>עָרְמַת הַפִּקֵחַ</strong> (cleverness/prudence of the discerning) is to understand his way — the same root <em>ʿāram</em> used for the serpent\'s cleverness in Gen 3:1; context determines whether shrewdness is virtue or vice. The folly of fools is <em>mirmâ</em> (deception/deceit) — the MKT "self-deception" draws out the direction: fools deceive themselves first.</p>',
    "9": '<p><strong>אֱוִילִים יָלִיץ אָשָׁם</strong> — fools mock or scoff at the <em>ʾāšām</em> (guilt/guilt-offering). The word <em>ʾāšām</em> carries its full Levitical weight: the guilt offering was the mechanism for repairing a damaged relationship with God or others. Fools treat the concept of restitution/guilt as something to ridicule. Among the upright (<em>yəšārîm</em>), <em>rāṣôn</em> (favor/goodwill) is present.</p>',
    "10": '<p><strong>מַרַּת נַפְשׁוֹ</strong> (bitterness of his soul) — <em>mar</em> is the taste of gall, the physical sensation of grief. <em>Nephesh</em> here is the inner experiential self, inaccessible to outsiders. No stranger (<em>zār</em>) shares in its joy either — the same inaccessibility applies to gladness. The verse establishes the fundamental privacy of the inner life as an anthropological fact.</p>',
    "11": '<p><strong>בֵּית רְשָׁעִים</strong> (house of the wicked) will be destroyed (<em>yiššāmēd</em>, Niphal: will be caused to perish) — the house as a material symbol of the family line. The tent (<em>ʾōhel</em>) of the upright will flourish (<em>yiphrāḥ</em>). The pairing of "house" with "tent" is deliberate: even the more temporary structure of the upright outlasts the supposedly permanent house of the wicked.</p>',
    "12": '<p><strong>דֶּרֶךְ יָשָׁר לִפְנֵי-אִישׁ</strong> (a way straight before a man) — the initial assessment is positive, "straight/upright" by appearance. Its end (<em>ʾaḥărîteyhā</em>) is ways of death (<em>darkê-māvet</em>, plural: there are many such paths). The verse is a philosophical statement about the limits of self-evaluation and the danger of trust in one\'s own moral sense (cf. Prov 3:5–7).</p>',
    "13": '<p><strong>גַּם בִּשְׂחוֹק</strong> (even in laughter) the heart may be painful (<em>yikʾāb</em>, is in pain/hurt) — the imperfect here is present-tense observation: laughter does not guarantee inner peace. <strong>וְאַחֲרִיתָהּ שִׂמְחָה תוּגָה</strong> (and its end, joy is grief) — the feminine suffix on "its end" refers back to laughter; the grammatical trace is subtle. Joy contains the seed of its own reversal.</p>',
    "14": '<p><strong>מִדְּרָכָיו יִשְׂבַּע</strong> (from his own ways he will be satisfied/full) — the backslider (<em>sûg lēb</em>, one who turns away of heart) is sated with his own choices: the consequences he chose. The good man will be satisfied <em>mimmennû</em> (from himself, from within) — the prep <em>min</em> makes the source internal, suggesting genuine inner resource rather than external circumstance.</p>',
    "15": '<p><strong>פֶּתִי</strong> (<em>petî</em>, simple/naive one) — the naivety of inexperience, not malice; the term is used for the educable youth throughout Proverbs. <em>Yaʾamin</em> (believes) every word — the imperfect indicates habitual credulity. The prudent (<em>ʿārûm</em>) considers carefully (<em>yābîn ʾăšurô</em>, understands/discerns his step) — the verb <em>bîn</em> implies ongoing deliberation.</p>',
    "16": '<p><strong>חָכָם יָרֵא</strong> (a wise person fears) — the object is implied; the fear is of God and consequence. He turns from evil (<em>sār mērāʿ</em>). The fool (<em>kəsîl</em>) is <em>mitrabbēr</em> (overconfident, puffed up) and <em>bôṭēaḥ</em> (trusts/is secure) — the same root used for godly trust in God; the fool redirects that trust toward himself.</p>',
    "17": '<p><strong>קְצַר-אַפַּיִם</strong> (short of nostrils/anger, quick-tempered) — the Hebrew idiom for anger runs through the nostrils; <em>ʾapayyim</em> literally means nostrils, and a flaring nose signals fury. Verse 29 below pairs this with the positive: <em>ʾerek ʾapayyim</em> (long of nostrils, slow to anger). The anatomical metaphor is precise and visceral.</p>',
    "18": '<p><strong>נָחֲלוּ פְתָאיִם</strong> (the naive have inherited) folly (<em>ʾiwwelet</em>) — the verb <em>nāḥal</em> is the inheritance-word; folly becomes their estate, their portion. The prudent (<em>ʿărûmîm</em>) are crowned (<em>yaktiru</em>, Hiphil: will crown/encircle) with knowledge. The social and metaphorical resonance of <em>keter</em> (crown) elevates knowledge to royalty.</p>',
    "19": '<p><strong>שַׁחוּ</strong> (they bowed down, Qal perfect) — the prophetic perfect: the moral order demands this outcome so certainly that it is spoken as accomplished fact. Evil people bow before the good; the wicked kneel at the gates of the righteous. The gate (<em>šaʿar</em>) is the place of judgment and community life; the reversal happens precisely where honor is publicly distributed.</p>',
    "20": '<p><strong>גַּם לְרֵעֵהוּ</strong> (even by his neighbor) is hated (<em>yiśśānēʾ</em>) — the social isolation of poverty. The rich man (<em>ʿāšîr</em>) has many friends (<em>ʾōhăbîm rabbîm</em>, many lovers) — the word <em>ʾōhăbîm</em> (from <em>ʾāhab</em>, love) in a social context means those who are drawn to him; the same root used for genuine love here denotes transactional attachment to wealth.</p>',
    "21": '<p><strong>בָּז לְרֵעֵהוּ</strong> (despises his neighbor) <strong>חוֹטֵא</strong> (sins, is a sinner) — the participial form makes contempt for the neighbor a defining sin, not a minor failing. The one who shows grace (<em>mēḥônnēn</em>, Piel participle: continually shows grace) to the poor (<em>ʿănāyîm</em>) is called <em>ʾašrāyw</em> (blessed, happy) — the same beatitude form as Ps 1:1.</p>',
    "22": '<p><strong>חֹרְשֵׁי רָע</strong> (those who plow evil) — the agricultural metaphor: deliberate, sustained evil-cultivation. They <em>yitʿû</em> (go astray, wander) — the same verb used for straying sheep. Those who plan good (<em>ḥōrəšê ṭôb</em>) find <em>ḥesed wĕʾemet</em> (loyal love and faithfulness) — the covenant-pair that characterizes God\'s own character (Exod 34:6).</p>',
    "23": '<p><strong>בְּכָל-עֶצֶב</strong> (in all labor/painful toil) there is profit (<em>môtār</em>, something left over, surplus) — <em>ʿeṣeb</em> is the word used for the painful labor of Gen 3:17 (the curse); here it is the path to gain. <em>Debar śəpātayim</em> (word of lips) — mere talking — leads only to poverty. The contrast is between embodied action and verbal substitutes for it.</p>',
    "24": '<p><strong>עֲטֶרֶת חֲכָמִים עָשְׁרָם</strong> (the crown of the wise is their wealth) — <em>ʿōšer</em> (wealth) as the crowning achievement; the word carries both material and honorific weight. The folly of fools (<em>ʾiwwelet kəsîlîm</em>) is <em>ʾiwwelet</em> (folly) — the tautology is deliberate and damning: fools\' crown is simply their own foolishness, which they display unwittingly.</p>',
    "25": '<p><strong>עֵד אֱמֶת</strong> (witness of truth) <strong>מַצִּיל נְפָשׁוֹת</strong> (saves lives/souls) — <em>māṣal</em> in the Hiphil is a rescue/deliverance verb, used for God\'s deliverance in the Psalms. The false witness (<em>ʾēd šeqer</em>) breathes out (<em>yāpîaḥ</em>) lies (cf. 14:5) — the same breathing metaphor, the habitual effortlessness of deception.</p>',
    "26": '<p><strong>בְּיִרְאַת יהוה</strong> (in the fear of the LORD) is strong confidence (<em>mibtaḥ ʿōz</em>, a strong refuge/trust). The suffix <em>ûbānāyw</em> (and for his children) — God\'s covenant with the God-fearer extends to the next generation; the fear of the LORD as an inherited orientation and social structure.</p>',
    "27": '<p>This verse is nearly identical to 13:14: <strong>יְרֵאַת יהוה מְקוֹר חַיִּים</strong> (fear of the LORD is a fountain of life). The repetition is deliberate and structural; the wisdom collection reinforces its core affirmations by recurrence. The fountain of life is not an abstraction but a relational orientation toward God that produces vitality.</p>',
    "28": '<p><strong>בְּרָב-עָם</strong> (in the abundance/multitude of people) is a king\'s glory (<em>hadar</em>) — the same word used for God\'s splendor in the Psalms. The prince\'s ruin (<em>mahattâ</em>, downfall) is the lack of people (<em>bĕʾepes leʾōm</em>, in the absence of a nation) — power is measured in persons, not territory. Leadership is relational.</p>',
    "29": '<p><strong>אֶרֶךְ אַפַּיִם</strong> (<em>ʾerek ʾapayyim</em>) — literally "long of nostrils," the anatomical idiom for patience/slowness to anger, contrasting with <em>qəṣar-ʾapayyim</em> (short of nostrils, v. 17). The contrast shows great insight (<em>rab-tebûnâ</em>, abundant understanding) — <em>tebûnâ</em> is not raw intelligence but the discernment that comes from understanding relationships and consequences. A quick temper (<em>qəṣar-rûaḥ</em>, short of spirit) elevates foolishness: makes it prominent, lifts it up.</p>',
    "30": '<p><strong>לֵב מַרְפֵּא</strong> (a healing heart) is <em>ḥayyê bāśār</em> (life of flesh/the body) — the inner emotional state of the heart (<em>lēb</em>) generates the physical vitality of the whole body. <em>Qinʾâ</em> (envy/jealousy) rots the bones (<em>raqqab-ʿăṣāmôt</em>) — the same verb used for decay and putrefaction; the emotion produces biological deterioration. The psychosomatic connection is explicit.</p>',
    "31": '<p><strong>עֹשֵׁק דָּל</strong> (oppressor of the poor) insults (<em>ḥērēp</em>) his Maker — the same word used for the Philistine\'s taunting of Israel (Goliath). To oppress the poor is to mock God as Creator. The one who shows grace (<em>mēḥannēn</em>) to the needy honors him (<em>məkabbədhô</em>) — the Piel of <em>kābad</em>, to give weight, to honor.</p>',
    "32": '<p><strong>בְּרָעָתוֹ יִדָּחֶה רָשָׁע</strong> (in his evil the wicked is thrust down/driven away) — the passive Niphal: his own evil is the agent. <strong>חֹסֶה בְמוֹתוֹ צַדִּיק</strong> (the righteous has refuge in his death) — <em>ḥāsâ</em> (take refuge) is the verb of shelter and trust used throughout the Psalms. <em>Bəmôtô</em> (in his death) is striking: the righteous person\'s hope in the moment of death itself.</p>',
    "33": '<p><strong>בְּלֶב נָבוֹן תָּנוּחַ חָכְמָה</strong> (in the heart of the discerning wisdom rests quietly) — <em>tānûaḥ</em> (rests, settles) is the verb of the Sabbath rest; wisdom finds a home in the discerning heart. Among fools (<em>bəqereb kəsîlîm</em>), wisdom "makes itself known" (<em>tiggāḏaʿ</em>, Niphal: is made known, reveals itself) — even unintentional disclosure; wisdom cannot be entirely suppressed even in fool company.</p>',
    "34": '<p><strong>צְדָקָה תְּרוֹמֵם-גּוֹי</strong> (righteousness lifts up a nation) — the verb <em>rûm</em> in the Polel is a stately elevation; <em>ṣedāqâ</em> as the national character creates social height. <em>Ḥesed</em> (in many translations "reproach"; others "loyal love/steadfast love") — here <em>ḥaṭṭāʾt</em> (sin/sin-offering) is the subject: "sin is the shame of peoples." The MKT "sin brings disgrace" follows the more common reading.</p>',
    "35": '<p><strong>רְצוֹן-מֶלֶךְ</strong> (favor of the king) — <em>rāṣôn</em> is the same word as divine acceptance or favor; royal and divine approval run in parallel in wisdom literature. The servant who acts wisely (<em>meskîl</em>, Hiphil participle: causes insight/acts intelligently) receives this. The king\'s wrath (<em>ʾapô</em>, his nose/anger) falls on the shameful (<em>mēbîš</em>, one who causes shame).</p>'
  },
  "15": {
    "1": '<p><strong>מַעֲנֶה רַּךְ</strong> (<em>maʿăneh rak</em>, a soft/gentle answer) — <em>maʿăneh</em> is the response that meets a question or situation; <em>rak</em> is soft, tender. The verb <em>yāšîb ḥēmâ</em> (turns away wrath) uses the return/restore verb: the soft answer sends wrath back the way it came. A grievous word (<em>debar-ʿeṣeb</em>, a word of pain/toil) stirs up (<em>yaʿăleh</em>, causes to rise) wrath — the uprising image of anger inflamed.</p>',
    "2": '<p><strong>לְשׁוֹן חֲכָמִים</strong> (tongue of the wise) <strong>תֵּיטִיב דָּעַת</strong> (presents knowledge rightly/makes knowledge good) — the Hiphil of <em>yāṭab</em>: causes knowledge to be good, presents it well. The mouth of fools (<em>pî כְּסִילִים</em>) <em>yabbîaʿ</em> (gushes/pours out) foolishness — the same word used for springs and fountains overflowing; uncontrolled output.</p>',
    "3": '<p><strong>עֵינֵי יהוה</strong> (eyes of the LORD) are in every place (<em>bəkol-māqôm</em>) — omnipresence stated plainly. They watch (<em>ṣōpôt</em>, Qal participle: constantly surveying) both the evil and the good. The theological import: there is no hidden space. The verse functions as the epistemological foundation for the entire Proverbs moral system — behavior is always observed.</p>',
    "4": '<p><strong>מַרְפֵּא לָשׁוֹן</strong> (a healing tongue) is a <em>ʿēṣ ḥayyîm</em> (tree of life) — the Genesis phrase again (cf. 13:12). The tongue as a tree of life: speech as a life-giving or life-denying force. <em>Selep</em> (crookedness/perverseness) in it is a breaking of the spirit (<em>šeber bərûaḥ</em>) — the same <em>šābar</em> used for the breaking of bones and the fracture of nations; twisted speech destroys at that depth.</p>',
    "5": '<p><strong>אֱוִיל</strong> (<em>ʾĕwîl</em>) — one of several Hebrew words for fool; this one emphasizes moral stubbornness rather than mere ignorance. He despises (<em>yinʾaṣ</em>, Qal: holds in contempt) his father\'s <em>mûsār</em> (discipline). The one who guards (<em>šōmēr</em>, keeps watch over) reproof (<em>tôkaḥat</em>) shows good sense (<em>yaʿrim</em>, acts prudently/craftily in the good sense).</p>',
    "6": '<p><strong>בֵּית צַדִּיק חֹסֶן רָב</strong> (house of the righteous is great treasure) — <em>ḥōsen</em> is the word for stored wealth or treasury; the household is a wealth-store not just materially but structurally. The income of the wicked (<em>tebûʾat rāšāʿ</em>) brings <em>ʿăkārâ</em> (trouble/disturbance) — the word used for Achan\'s troubling of Israel (Josh 7:25).</p>',
    "7": '<p><strong>שִׂפְתֵי חֲכָמִים</strong> (lips of the wise) <strong>יְזָרוּ דָעַת</strong> (spread/scatter knowledge) — the verb <em>zārâ</em> is used for winnowing grain; wisdom spread by speech is like grain scattered in the wind, broadcast generously. The heart (<em>lēb</em>) of fools — not their mouth — is not so (right/established) — the problem begins deeper than speech.</p>',
    "8": '<p><strong>זֶבַח רְשָׁעִים תּוֹעֲבַת יהוה</strong> (sacrifice of the wicked is an abomination of the LORD) — <em>tôʿăbâ</em> is the cultic revulsion-word: what is fundamentally incompatible with God\'s holiness, specifically what violates covenant relationship. Sacrifice without inner righteousness is not merely ineffective; it is actively offensive. <em>Tephilat yəšārîm</em> (prayer of the upright) is his <em>raṣôn</em> (delight/pleasure/favor).</p>',
    "9": '<p>The double use of <strong>תּוֹעֲבַת יהוה</strong> in vv. 8–9 (sacrifice, then the way/lifestyle of the wicked) intensifies: not just cultic performance but life-orientation provokes divine revulsion. God <em>yəʾahab</em> (loves, Piel: deeply loves) whoever earnestly pursues (<em>məraddēp</em>, Piel participle: continuously, hotly pursues) righteousness — the verb suggests relentless chase.</p>',
    "10": '<p><strong>מוּסָר רָע</strong> (evil/harsh discipline) for the one who <em>ʿōzēb ʾōraḥ</em> (forsakes the path/way) — the abandonment of the way earns painful discipline. <em>Śōnēʾ tôkaḥat</em> (hater of reproof) will die — the imperfect is stark: this is the trajectory. The connection is not mechanical punishment but the internal logic of rejecting the corrective that sustains life.</p>',
    "11": '<p><strong>שְׁאוֹל וַאֲבַדּוֹן</strong> (<em>Šəʾôl wəʾăbaddôn</em>) — the paired names for the realm of death; <em>Abaddon</em> means destruction/perdition (from <em>ʾābad</em>, to perish). Both "lie open (<em>nəgêd</em>, before/visible) to the LORD" — the underworld is not hidden from divine sight. The rhetorical <em>ʾap kî</em> (how much more): if even death\'s domain is transparent to God, how much more are human hearts.</p>',
    "12": '<p><strong>לֵץ לֹא-יֶאֱהַב</strong> (the mocker does not love) being reproved (<em>hōkêaḥ lô</em>) — the same <em>ʾāhab</em> (love) as genuine attachment; the mocker\'s aversion to correction is visceral and defining. He will not go (<em>wəʾel-ḥăkāmîm lōʾ yēlēk</em>) to the company of the wise — self-isolation from the corrective community is the mocker\'s chosen condition.</p>',
    "13": '<p><strong>לֵב שָׂמֵחַ</strong> (a joyful/glad heart) makes the face (<em>pānîm</em>) good (<em>yêṭib</em>, Hiphil: causes the face to be good) — the inward state shows outwardly. A crushed spirit (<em>bəʿaṣbat-rûaḥ</em>) — <em>ʿaṣab</em> is pain/grief/toil — breaks/bows (<em>nəkēʾâ rûaḥ</em>) the spirit. The psychosomatic connection is explicit in both directions: inner peace radiates outward; inner grief collapses inward.</p>',
    "14": '<p><strong>לֵב נָבוֹן</strong> (a discerning heart) is always seeking (<em>yəbaqquēš</em>, Piel: continuously, intensively seeks) knowledge (<em>dāʿat</em>). The mouth of fools (<em>pî kəsîlîm</em>) feeds (<em>yirʿeh</em>, literally grazes/shepherds) on folly — the pastoral metaphor is precise: fools graze on foolishness as naturally as sheep on grass. The contrast is active seeking vs. passive consumption of one\'s default diet.</p>',
    "15": '<p><strong>כָּל-יְמֵי עָנִי רָעִים</strong> (all the days of the afflicted are evil) — <em>ʿānî</em> is the poor/afflicted/oppressed person; their subjective experience of daily life is consistently bad. But a good heart (<em>ṭôb-lēb</em>) is a continual feast (<em>mišteh tāmîd</em>) — <em>mišteh</em> is a banquet/drinking feast; the contrast is between the bleakness of external poverty and the inner abundance of the joyful heart. The inner life can override external conditions.</p>',
    "16": '<p><strong>בְּיִרְאַת יהוה</strong> (with the fear of the LORD) accompanying little (<em>məʿaṭ</em>) is better (<em>ṭôb</em>) than great treasure (<em>ʾôṣār rāb</em>) with turmoil (<em>ûmehûmâ bô</em>) — <em>mehûmâ</em> is the panic and tumult of battle or disaster; wealth without divine orientation generates its own chaos. The <em>ṭôb</em> (better-than) formula is a wisdom rhetorical device for relative evaluation.</p>',
    "17": '<p><strong>אֲרֻחַת יָרָק</strong> (a portion of herbs/vegetables) with love (<em>ʾahăbâ</em> šām, love being there) is better than <em>šôr ʾăbûs</em> (a fattened ox) with hatred (<em>śinʾâ bô</em>). The <em>ʾăbûs</em> (stall-fed) ox is the luxury meal. The relational quality of the meal determines its nourishment more than the food itself.</p>',
    "18": '<p><strong>אִישׁ חֵמָה</strong> (a man of wrath/heat) stirs up (<em>yəgāreh</em>, Piel: provokes, picks a fight with) strife (<em>māḏôn</em>). The one slow to anger (<em>ʾerek ʾapayyim</em>, long of nostrils — the same idiom as 14:29) quiets (<em>yəšakkēn</em>, Piel: causes to dwell/settle) strife. The Piel in both cases intensifies: the provocation is deliberate, and the quieting is active work.</p>',
    "19": '<p><strong>דֶּרֶךְ עָצֵל</strong> (way of the lazy) is like a hedge of thorns (<em>kəמְשׂוּכַת קוֹצִים</em>) — <em>məśûkâ</em> is a barrier of thorns, an impenetrable wall. The road of the upright (<em>ʾōraḥ yəšārîm</em>) is a level highway (<em>səlullâ</em>, a built-up road, the kind paved for royal procession). The contrast is not just easy vs. hard but organic obstacle vs. constructed path.</p>',
    "20": '<p><strong>בֵּן חָכָם</strong> (a wise son) makes his father glad (<em>yəśammēaḥ-ʾāb</em>, Piel: causes joy to his father). A foolish man (<em>ûkəsîl אָדָם</em>) despises his mother (<em>bôzeh ʾimmô</em>) — the contempt word. The shift from "son" to "man" in the second half is deliberate: the grown fool, who should have matured, still acts like the scorner of ch. 13:1.</p>',
    "21": '<p><strong>אִוֶּלֶת שִׂמְחָה לַחֲסַר-לֵב</strong> (folly is joy/entertainment to the one lacking heart/understanding) — <em>ḥăsar-lēb</em> (lacking heart) is the Proverbs phrase for the person without moral judgment; folly actually brings them pleasure. The person of understanding (<em>ʾîš tebûnâ</em>) walks straight (<em>yəyaššer-lāket</em>) — the causative of <em>yāšar</em>: makes his walking straight, corrects his own course.</p>',
    "22": '<p><strong>הֲפֵר מַחֲשָׁבוֹת</strong> (plans come to nothing/are frustrated) where there is no counsel (<em>bəʾên sôd</em>) — <em>sôd</em> is the intimate counsel of a close group, the divine council language used in Amos 3:7 and Jer 23:18. With the multitude of advisors (<em>bərōb yôʿăṣîm</em>) plans are established (<em>tāqûm</em>, will stand/arise). The wisdom of collaborative discernment echoes the divine council pattern.</p>',
    "23": '<p><strong>שִׂמְחָה לָאִישׁ בְּמַעֲנֵה-פִיו</strong> (joy belongs to a person in the answer of his mouth) — the joy of giving the right word; <em>maʿăneh</em> (answer/response) is the same root as 15:1. The rhetorical question <em>ûדָבָר בְּעִתּוֹ מַה-טּוֹב</em> (a word in its time, how good it is!) — <em>ʿittô</em> (its time, the right moment): timing is as important as content.</p>',
    "24": '<p><strong>אֹרַח חַיִּים לְמַעְלָה</strong> (the path of life leads upward) — <em>ləmaʿlâ</em> is a spatial-moral indicator: upward, heavenward. The purpose clause: <em>לְמַעַן סוּר מִשְּׁאוֹל מָטָּה</em> (in order to turn from Sheol below) — the spatial antithesis is complete. The wise person\'s life-trajectory is upward, away from the downward pull toward the realm of death.</p>',
    "25": '<p><strong>בֵּית גֵּאִים</strong> (house of the proud) will be torn down (<em>yissaḥ</em>, Qal: uprooted/pulled apart) by the LORD — direct divine action. The widow\'s property line (<em>גְּבוּל אַלְמָנָה</em>) he maintains (<em>yaṣṣēb</em>, Hiphil: causes to stand, maintains firmly). The widow as the paradigmatic vulnerable person in Israelite law; the LORD as her boundary-keeper against the encroachment of the powerful.</p>',
    "26": '<p>The third use of <strong>תּוֹעֲבַת יהוה</strong> in chapter 15 (vv. 8, 9, 26) — now applied to the plans (<em>maḥšəbôt</em>) of the wicked. Pure words (<em>ʾimrê-ṭōhar</em>, words of purity) are pleasing (<em>təhôrîm nōʿam</em>) to him — the same <em>nāʿam</em> (pleasantness) used for Wisdom\'s paths in Prov 3:17. The cultic and ethical are fused: purity of speech is liturgically acceptable.</p>',
    "27": '<p><strong>בּוֹצֵעַ בָּצַע</strong> (one who cuts/gains unjust gain) troubles (<em>ʿōkēr</em>) his household — the same verb used for Achan\'s troubling of Israel in Josh 7:25. <em>Śōnēʾ mattānôt</em> (hater of bribes) will live — not merely "survives" but <em>yiḥyeh</em> (will have life), the full life that wisdom promises. The ethical and the vital are inseparably linked.</p>',
    "28": '<p><strong>לֵב צַדִּיק</strong> (heart of the righteous) <strong>יֶהְגֶּה</strong> (meditates/weighs carefully) before answering — <em>hāgâ</em> is the meditation verb of Ps 1:2 (meditating on Torah). The speech of the righteous is the outcome of inner deliberation. The mouth of the wicked (<em>pî rəšāʿîm</em>) <em>yabbîaʿ</em> (gushes, same as 15:2) evil things — unfiltered overflow without prior thought.</p>',
    "29": '<p><strong>רָחוֹק יהוה מֵרְשָׁעִים</strong> (the LORD is far from the wicked) — <em>rāḥôq</em> (distant) as a spatial metaphor for relational absence. This is not merely metaphor: in wisdom theology, the distance is the consequence of choosing the path that diverges from God. He hears (<em>yišmaʿ</em>) the prayer of the righteous — the covenant hearing-response formula; prayer reaches God because proximity exists.</p>',
    "30": '<p><strong>מְאוֹר-עֵינַיִם</strong> (light of eyes, bright eyes) makes the heart glad (<em>yəśammah-lēb</em>) — a psychosomatic chain running from the visual sense to the emotional center. Good news (<em>šəmûʿâ ṭôbâ</em>) refreshes (<em>tədaššen</em>, causes to be fat/prosperous) bone — <em>dāšan</em> means to become fat or well-nourished; the idiom suggests deep physical restoration from within.</p>',
    "31": '<p><strong>אֹזֶן שֹׁמַעַת תּוֹכַחַת חַיִּים</strong> (ear that listens to life-giving correction) — <em>tôkaḥat ḥayyîm</em> (reproof of life, life-giving reproof): the correction that leads to life is so described. The one who heeds it <em>bəqereb ḥăkāmîm tālin</em> (lodges/dwells among the wise) — <em>lîn</em> is an overnight lodging verb; the correction-hearer makes a permanent home in the company of wisdom.</p>',
    "32": '<p><strong>פּוֹרֵעַ מוּסָר</strong> (one who neglects/throws off discipline) <strong>מוֹאֵס נַפְשׁוֹ</strong> (despises his own nephesh) — the person who refuses correction injures the very self they meant to protect. By contrast, <em>šōmēaʿ tôkaḥat qōneh lēb</em> (whoever listens to reproof gains/acquires heart/understanding) — <em>qānâ</em> is the acquisition verb used for buying wisdom (4:5, 7); correction is a purchase that yields understanding.</p>',
    "33": '<p><strong>יִרְאַת יהוה מוּסַר חָכְמָה</strong> (fear of the LORD is training/discipline for wisdom) — <em>mûsar</em> (discipline/instruction) is the same word that opens ch. 1:2; it closes ch. 15 to form a structural bracket. Wisdom is not innate but acquired through the fear-shaped formative process. <em>Liphney kābôd ʿănāwâ</em> (before honor is humility) — <em>ʿănāwâ</em> (humility, meekness) precedes honor; the sequence matters.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'proverbs')
    merge_comm(existing, PROVERBS)
    save_comm('mkt-original', 'proverbs', existing)
    print('Proverbs 13–15 mkt-original written.')

if __name__ == '__main__':
    main()
